/** Textos, contacto y horarios desde ovalleturismo.cl */
export const OFFICIAL_CONTENT: Record<string, Partial<Ficha>> = {
  "angel-calameno": {"description": "Ubicado en El Espinal, camino a Sotaquí, en la comuna de Ovalle, El Ángel Calameño es mucho más que un restaurante: es un refugio donde la tradición chilena y la naturaleza se entrelazan para ofrecer una experiencia memorable. Muchos visitantes lo describen como un espacio que refleja una atmósfera llena de naturaleza y calidez familiar. Esta pincelada de misterio contribuye a su encanto y genera curiosidad en los viajeros que buscan algo auténtico en Limarí. Se destaca por un entorno acogedor y campestre, rodeado de vegetación exuberante, jardines encantadores y un estilo rústico que invita al descanso y al disfrute. Lo cual los convierte en un oasis en medio del valle, ideal para quienes buscan desconexión y buena gastronomía.", "phone": "+56 9 97480804", "email": "angelcalamenoovalle@gmail.com", "schedule": "Lunes a jueves 09:00 a 22:00 hrs. Viernes y sábado 09:00 a 04:00 hrs. Domingo 09:00 a 21:00 hrs.", "details": ["Si eres un turista explorando Ovalle y sus alrededores, El Ángel Calameño es una parada obligada: un rincón donde lo rústico y lo íntimo se combinan con platos sabrosos, la naturaleza como escenario y una atención que enamora. Ya sea para un almuerzo en familia, un evento especial o un momento de descanso placentero, este lugar te ofrece una experiencia chilena auténtica y memorable."], "relatedIds": ["riquisimo", "cabildo-abierto", "plaza-terraza", "kata-resto-bar"]},
  "apart-hotel-dolce-vita": {"description": "El Apart Hotel Dolce Vita, situado en Ovalle, ofrece vistas al río, WiFi gratuita y aparcamiento privado gratuito.", "phone": "(56) 9 57032005", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hacienda-huamalata", "hotel-florencia", "hotel-termas-socos", "ovalle-suite", "keo-hotel", "hotel-limari"]},
  "blackcoffe": {"description": "Emprendimiento 100% ovallino que llega a conquistar el corazón del paseo peatonal con una propuesta única: una Cafetería y RestoBar imperdible , donde se combina el encanto local con un servicio de primer nivel. Su carta invita a disfrutar de un café de especialidad premium, alta pastelería con ese inconfundible sabor casero de la abuela y helados artesanales de excelencia. Al caer la tarde, el ambiente se transforma para ofrecer una experiencia relajada y entretenida, con coctelería internacional, tablas para compartir, sándwiches gourmet y las infaltables chorrillanas chilenas. Un espacio ideal para disfrutar Ovalle en todo su sabor.", "phone": "+56 9 3622 4511", "email": "coffe6762@gmail.com", "schedule": "Invierno de 09:00 a 20:00 hrs. Verano de 10:00 a 21:00 hrs.", "relatedIds": ["poki-bubble-tea", "cafe-carmen", "rincon-de-los-postres", "cafe-vittoria"]},
  "cabanas-fray-jorge": {"phone": "(56) 9 8544 0682", "email": "robertoaraya44@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["los-pumas-encanto", "viento-sur", "trapiche-lodge", "descanso-antakari", "cabanas-stommeln"]},
  "cabanas-stommeln": {"description": "Ubicadas muy cerca de una de las arterias principales de Ovalle las Cabañas Stommeln se han convertido en el alojamiento preferido por viajeros que quieren recorrer y conocer la localidad. Aunque también es usado como un centro de convenciones el recinto ofrece todas las comodidades necesarias para que disfrutes de tu estadía en el poblado. Cabañas completamente equipadas con cocina, sala de estar, baños privados y duchas calientes. Cada cabaña está diseñada para garantizar tranquilidad y serenidad a los huéspedes, cuentan con suite principal y cama matrimonial, una habitación secundaria con camas individuales. En la parte frontal cuenta con terraza con vistas a la piscina. Puedes realizar reuniones y celebraciones familiares en la zona de quincho con parrilla para asados. Extensas áreas verdes son perfectas para jugar y disfrutar con los pequeños de la familia, además cuenta con una piscina al aire libre abierta al público durante todo el año.", "phone": "(56) 9 97834997", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["los-pumas-encanto", "viento-sur", "trapiche-lodge", "descanso-antakari", "cabanas-fray-jorge"]},
  "cabildo-abierto": {"description": "Cabildo Abierto restaurant es una empresa familiar, que se dedica a atender el flujo de clientes que visitan Barraza, tematizado en la cultura diaguita y con énfasis en la arquitectura del tiempo de la colonia, de las viviendas de los peones, que utilizaban los materiales locales para construir sus viviendas techos de totora y estructuras de quincha donde el barro es el elemento principal de las construcciones.", "phone": "+56 9 94255367", "email": "cabildoabiertobarraza@gmail.com", "schedule": "Lunes a viernes solo con reserva. Sábado y domingo desde las 12:00 hrs.", "relatedIds": ["riquisimo", "plaza-terraza", "kata-resto-bar", "angel-calameno"]},
  "cafe-carmen": {"description": "Ubicado en pleno corazón de Ovalle, a una cuadra de la plaza, Café Carmen abre sus puertas en una casa tradicional ovallina refaccionada, conservando el encanto de lo clásico y transformándola en un espacio tranquilo para disfrutar de un buen café. Su propuesta une grano y sándwich, con una carta que incluye opciones tradicionales y de la casa, pensadas para acompañar cada visita. Dentro de nuestras preparaciones, el Latte Carmen ya se ha posicionado como el favorito de quienes los han visitado, y esperan seguir creciendo como un nuevo panorama ovallino.", "schedule": "Lunes a Viernes de 08:00 a 20:00 hrs.", "relatedIds": ["poki-bubble-tea", "blackcoffe", "rincon-de-los-postres", "cafe-vittoria"]},
  "cafe-vittoria": {"description": "Café Vittoria es una cafetería de especialidad ubicada en pleno centro de Ovalle, que invita a vivir una experiencia acogedora, con café de origen, tés selectos, jugos naturales, pastelería artesanal, sandwiches y opciones gourmet para desayunos y almuerzos livianos. Su sello es la calidad en cada taza y una atención personalizada y cercana. Ofrecen un ambiente cálido, ideal para compartir, leer, trabajar o simplemente disfrutar de un buen momento. Trabajan con granos seleccionados para máquina de espresso y métodos de filtrado. Su café, la atención de nuestros baristas y una carta que equilibra sabores dulces y salados para todos los gustos, buscan entregar una experiencia destacada en la ciudad, tanto para conocedores del café como para quienes busquen un lugar especial. Café Vittoria es también un espacio que busca generar cultura cafetera en la ciudad, con horario extendido y un concepto de café boutique que inspira tranquilidad y disfrute.", "schedule": "Lunes a viernes 07:30 a 20:00 hrs. Sábado a domingo 08:30 a 19:00 hrs. Domingo cerrado.", "relatedIds": ["poki-bubble-tea", "cafe-carmen", "blackcoffe", "rincon-de-los-postres"]},
  "caprinos-villaseca": {"description": "Cap ri nos Villaseca es una destacada empresa familiar ubicada en la localidad de Villaseca, en la comuna de Ovalle, Región de Coquimbo. Fundada por Yasna Molina, quien fue galardonada con el «Premio Nacional a la Mujer Innovadora en Agricultura 2022» por la Fundación para la Innovación Agraria (FIA), la empresa se dedica a la crianza de cabras y a la elaboración artesanal de quesos finos a base de leche de cabra .", "phone": "+56 9 5189 3427", "email": "yasna.molina79@gmail.com", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "cooperativa-pisquera": {"description": "Pisquera Control representa la esencia del pisco chileno: una bebida de calidad, elaborada con tradición y pasión por pequeños productores que han sabido adaptarse a los desafíos del tiempo sin perder su identidad. Su historia es un testimonio del esfuerzo colectivo y la resiliencia de las comunidades rurales del Valle del Limarí. Una visita a la cooperativa es una oportunidad para conocer de cerca este legado y disfrutar de uno de los destilados más emblemáticos de Chile.", "phone": "+569 56654120", "relatedIds": ["macero-sour", "pisco-ovalle", "vina-tololo", "espumante-azur"]},
  "descanso-antakari": {"description": "Cabañas Refugio Antakari es un alojamiento turístico ubicado en Río Hurtado, Chile . Cuenta con una calificación de 5.0 estrellas basada en 51 reseñas .", "phone": "(56) 9 41458670", "email": "descansoantakari@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["limari-aventura", "poki-bubble-tea", "riquisimo", "cabildo-abierto", "macero-sour", "exp-enraizada"]},
  "desembocadura-limari": {"description": "Ubicada dentro de la Reserva de la Biosfera Fray Jorge , la desembocadura del Río Limarí es un verdadero tesoro natural donde se encuentran las aguas continentales con el océano, generando un ecosistema rico y diverso. Este espacio alberga una alta diversidad biológica , con más de 170 especies de aves autóctonas y migratorias . Durante los meses cálidos, es posible observar becacinas, gaviotas garumas, huairavillos, garzas cucas, patos cuchara, cisnes coscoroba y cisnes de cuello negro, entre muchas otras. En invierno, también llegan aves altiplánicas como la gaviota andina y el flamenco chileno. Gracias a su escasa intervención humana , en 2013 este lugar fue reconocido como el primer sitio “Starlight” de Sudamérica , certificación que lo distingue por sus cielos nocturnos libres de contaminación.", "details": ["La Desembocadura del Río Limarí es un destino ideal para el ecoturismo, la fotografía, la observación de aves y la educación ambiental . Un lugar perfecto para quienes buscan contemplar la naturaleza en su estado más puro y reconectarse con la tranquilidad del entorno."]},
  "don-giorgio": {"description": "Con casi 30 años de trayectoria, Pizzería Don Giorgio se ha consolidado como un verdadero referente gastronómico en Ovalle. Desde 1996, se ha destacado por su masa artesanal a la piedra y una amplia variedad de ingredientes frescos, ofrece pizzas únicas que combinan sabores clásicos y propuestas innovadoras como la Raffaela, Isabella y opciones vegetarianas como la Francisca. El ambiente cálido y familiar hace que cada visita sea una experiencia especial, ideal tanto para una salida en pareja como para compartir con amigos o la familia. Su equipo se caracteriza por una atención cercana y cordial, lo que convierte cada comida en un momento agradable. Pronto a celebrar tres décadas de historia, Don Giorgio sigue siendo sinónimo de calidad, dedicación y sabor inconfundible, manteniéndose como una de las mejores opciones para disfrutar de una verdadera Pizza en Ovalle.", "phone": "+56 9 77986964", "email": "pizzeriadongiorgio@gmail.com", "schedule": "Lunes a miércoles 12:30 a 22:00 hrs. Jueves a sábado 12:30 a 22:30 hrs. Domingo cerrado.", "relatedIds": ["la-lia-pizza", "hotel-italia"]},
  "ecocamping-munay": {"description": "A poco más de 5 minutos de la Ruta 5 Norte y emplazado casi a los pies del Río Limarí, ubicado en sitio RAMSAR destacado por su biodiversidad, encuentras Ecocamping Puntilla Munay, un destino encantador para familias y visitantes que buscan relajarse y desconectarse de lo diario. Ecocamping Puntilla Munay es un proyecto familiar cuyo valor agregado es el de contemplar y cuidar la naturaleza aledaña debido a su cercanía y compromiso con el cuidado del medio ambiente. Además, sus instalaciones combinan la armonía y tranquilidad con un conjunto de servicios disponibles para todos los visitantes. Reúne lo mejor del entorno natural con grandes vistas, unos cielos despejados la mayor parte del año y una variedad importante de flora y fauna protegida.", "phone": "(56) 9 61314901", "email": "contacto@puntillamunay.cl", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["los-pumas-encanto", "viento-sur", "descanso-antakari"]},
  "espumante-azur": {"description": "Azur nació como la primera bodega chilena dedicada exclusivamente a la producción de espumantes bajo el método tradicional, inspirado en las grandes casas de Champagne y Franciacorta . Fundada por Rafael Guilisasti, Stefano Rossi y Fabio Mascialino , la bodega cuenta con la asesoría técnica del enólogo italiano Carlo Franchini. Desde 2014, Azur emprendió la transición hacia la agricultura orgánica, culminando con su primera cosecha certificada en 2018 .", "phone": "(56) 9 28338383", "email": "info@azur.cl", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["macero-sour", "pisco-ovalle", "vina-tololo", "cooperativa-pisquera"]},
  "exp-caprinos": {"description": "Cap ri nos Villaseca es una destacada empresa familiar ubicada en la localidad de Villaseca, en la comuna de Ovalle, Región de Coquimbo. Fundada por Yasna Molina, quien fue galardonada con el «Premio Nacional a la Mujer Innovadora en Agricultura 2022» por la Fundación para la Innovación Agraria (FIA), la empresa se dedica a la crianza de cabras y a la elaboración artesanal de quesos finos a base de leche de cabra .", "phone": "+56 9 5189 3427", "email": "yasna.molina79@gmail.com", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "exp-dalbosco": {"description": "En un estrecho valle que cruza desde la cordillera de Los Andes hasta el Océano Pacífico, en el corazón del Valle del Limarí, en Punitaqui, se encuentra Viña Dalbosco. Este estrecho valle es un verdadero tesoro vitivinícola, reconocido por sus singulares microclimas que permiten obtener uvas de calidad excepcional. De ellas nacen una gran variedad de vinos elegantes, de intenso color, gran cuerpo y frutosidad que refleja la esencia del valle. Visitar Viña Dalbosco es más que una experiencia enológica: es un encuentro con la tradición, la naturaleza y la pasión por el vino. Te invitamos a recorrer nuestros viñedos, descubrir los secretos de su elaboración y disfrutar de degustaciones que despiertan los sentidos.", "phone": "(56) 9 99979777", "email": "info@dalboscowines.cl", "schedule": "Horario continuado. Lunes a jueves de 8:30 a 18:00 hrs. Viernes de 8:30 a 17:00 hrs. Sábado de 10:00 a 14:00 hrs.", "details": ["Ven, descubre y vive la magia del Valle del Limarí a través de los vinos…", "Disponibilidad de tours: Si, con aviso previo (no tenemos capacidad máxima porque hemos atendido buses de adultos mayores)."], "relatedIds": ["macero-sour", "pisco-ovalle", "vina-tololo", "espumante-azur"]},
  "exp-enraizada": {"description": "Terapias Holísticas Enraizada es un espacio de bienestar que conecta cuerpo, mente y espíritu en armonía con la naturaleza ovallina. A través de prácticas como biomagnetismo, Gemoterapia en cama de cuarzo solarizada, masajes relajantes, tinajas de agua caliente, yoga y Meditaciones, sumando la innovación de una máquina de Desintoxicación iónica, se ofrece un camino de sanación integral que invita a reconectar con la raíz interior y liberar energías bloqueadas. Con un enfoque místico y natural, cada experiencia está diseñada para equilibrar emociones, renovar la energía vital y fomentar un profundo estado de paz y relajación. Enraizada es más que un servicio: es un viaje de transformación y autoconocimiento, donde la sanación comienza desde tu raíz. 🌿✨", "phone": "+56 974300093", "email": "terapiasenraizada@gmail.com", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "exp-las-majadas": {"description": "Quesos Las Ma j a das es una empresa que elabora quesos artesanales de cabra utilizando leche pasteurizada. Entre sus productos más destacados se encuentran el Queso Cabrita Ma lpaso , ma durado en pisco y hojas de parra comestibles, y el Queso Ma durado en Vino , que se caracteriza por su aro ma y sabor únicos. La empresa ha sido reconocida por su excelencia en la producción de quesos y ha recibido premios en competencias internacionales.", "phone": "+56 9 8129 7729", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "exp-qori": {"description": "Es un producto gourmet de excelencia, fruto del cli ma único del Li ma rí, de un blend cuida doso y una extracción industrial especializada. Ideal para quienes buscan un aceite fresco, equilibrado y con carácter, accesible desde su origen en Ovalle hasta mesas exigentes.", "phone": "(56) 9 92222054", "email": "claudimoreno@qori.cl", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "exp-tulahuen": {"description": "La Pisquera Tulahuén es reconocida por elaborar dos de los piscos más destacados de Chile: Pisco Waqar y Pisco Heron . Con una tradición familiar y un proceso de producción artesanal, esta pisquera combina el saber ancestral con técnicas modernas para crear destilados de calidad internacional. Su ubicación en la localidad de Tulahuén, Monte Patria, le otorga características únicas, ya que las uvas crecen bajo cielos despejados y en un clima privilegiado que potencia sus aromas y sabores. Visitar la Pisquera Tulahuén es una experiencia donde se puede conocer de cerca el proceso de destilación, recorrer sus instalaciones y, por supuesto, degustar piscos que han sido reconocidos en competencias nacionales e internacionales por su elegancia y autenticidad.", "phone": "+569 85700189", "email": "CONTACTO@PISQUERATULAHUEN.CL", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "exp-waqar": {"description": "Elaborado por Pisquera Tulahuén con 170 años de tradición, PISCO WAQAR es un destilado ultra premium con denominación de origen, elaborado a escala humana a partir de vino chileno, obtenido 100% de uvas moscatel cultivadas en un terruño puro y ancestral a los pies de los Andes, y aun cosechadas a mano. A los sentidos WAQAR es transparente, joven y prístino, fino y delicado, con cautivantes aromas a frutas blancas, cítricos y azahares. Al beber revela un delicioso sabor, redondo y seco, sin ardor molesto los aromas se desparraman en la boca transportándonos a la fruta fresca de los viñedos mientras un leve picor pincha los sentidos, al irse deja un grato recuerdo por un instante prolongado que se desvanece lenta y sutilmente.", "phone": "+569 85700189", "email": "CONTACTO@PISQUERATULAHUEN.CL", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "feria-modelo": {"description": "La Feria Modelo de Ovalle no es solo un mercado, sino un espacio vivo que fusiona comercio, patrimonio, cultura y gastronomía regional. Ideal para vivir una experiencia arraigada en la identidad limarina y explorar la riqueza productiva de la provincia.", "phone": "(56) 532 661289", "relatedIds": ["pueblo-barraza", "iglesia-san-vicente", "museo-limari", "valle-encanto"]},
  "fray-jorge": {"description": "Temporada baja (actual) – jueves a domingo 09:00 a 15:00 hrs. *Algunas restricciones que pueden afectar el ingreso al parque de un momento a otro, algunas restricciones son: cierres preventivos por condiciones de riesgo de Incendio Forestal, manutención del camino, intensas lluvias en invierno. Parque Nacional Bosque Fray Jorge es un parque nacional chileno, ubicado a solo 44 kilómetros de la ciudad de Ovalle, Región de Coquimbo. Es un área protegida única en el mundo, declarada Reserva de la Biosfera por la UNESCO. Lo que lo hace especial es la presencia de un bosque relicto de tipo valdiviano, propio del sur de Chile, en pleno norte semiárido, gracias a la influencia de la niebla costera o “camanchaca”.", "email": "parque.frayjorge@conaf.cl", "details": ["Este fenómeno climático permite la existencia de una vegetación exuberante, con helechos, musgos y arboles húmedos, que contrastan con el paisaje seco que lo rodea. Además de su valor ecologico, el parque ofrece senderos interpretativos, miradores con vistas al océano pacífico y una rica biodiversidad de flora y fauna endémica.", "Fray Jorge es un destino imprescindible para los amantes de la naturaleza, la observación científica y el turismo sustentable."]},
  "gran-hotel-ovalle": {"description": "Gran Hotel Ovalle se encuentra ubicado en el único paseo peatonal de la ciudad, a pasos del centro y tan solo 5 minutos del Terminal de Buses de Ovalle. Su cercanía a distintos servicios lo convierten en el lugar perfecto para quienes visiten la ciudad por motivos de negocios.", "phone": "(56) 9 65370266", "email": "granhotel210@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hacienda-huamalata", "hotel-florencia", "hotel-termas-socos", "ovalle-suite", "keo-hotel", "hotel-limari"]},
  "hacienda-huamalata": {"description": "Hacienda Huamalata es un exclusivo hotel y centro de eventos ubicado en el corazón del Valle del Limarí, a pocos minutos del centro de Ovalle. Rodeado de naturaleza, viñedos y tranquilidad, combina el encanto de su fachada original con una infraestructura moderna de estilo mediterráneo. El recinto ofrece alojamiento en habitaciones matrimoniales totalmente equipadas, además de piscina, terraza y spa con saunas y jacuzzi. Para eventos, Hacienda Huamalata dispone de un salón con capacidad para 70 personas y amplios jardines, permitiendo adaptar cada celebración al espacio que mejor se ajuste a las necesidades del cliente. Además, cuenta con una cocina completamente equipada, ideal para la realización de matrimonios, almuerzos, cenas u otras actividades.", "phone": "(56) 9 33822140", "email": "contacto@haciendahuamalata.cl", "schedule": "Restaurant Cannoli Jueves a sábado 12:00 a 22:00 hrs. Domingo 12:00 a 18:30 hrs.", "details": ["Es el lugar perfecto para descansar, celebrar y disfrutar del entorno único del Valle del Limarí, con atención cercana y un entorno natural privilegiado."]},
  "hacienda-santa-cristina": {"description": "Situados en el corazón del valle del Limarí, rodeados de Eucaliptos, Olivos y una variedad de flora nativa, usted podrá disfrutar del inmejorable y exquisito clima rural de nuestra zona, aquí en la Región de Coquimbo, que lo ha hecho merecedor de los más grandes reconocimientos a nivel nacional y mundial en la producción de piscos y vinos Premium. Empresa familiar y junto a su equipo de trabajo están siempre preocupados de entregar una atención personalizada y un servicio de primera calidad, permitiendo que sus clientes vivan una verdadera experiencia en este verdadero oasis en el Valle del Limarí. El lugar invita sus visitantes a disfrutar de paseos a caballo, recorrer pequeñas sendas que conducen a descubrir rincones inesperados, a contemplar el cielo nocturno lleno de estrellas y a relajarse en sus acogedoras tinas de madera.", "phone": "+56 9 98715269", "email": "contacto@haciendasantacristina.cl", "schedule": "Lunes a domingo: Almuerzo 13:00 a 15:30 hrs. Cena 19:30 a 21:30 hrs.", "relatedIds": ["riquisimo", "cabildo-abierto", "plaza-terraza", "kata-resto-bar"]},
  "heladeria-alex": {"phone": "+56 9 81382250", "schedule": "Invierno Lunes a Sábado 11:00 a 18:00 hrs. Domingo 11:00 a 18:00 hrs. Horario Verano Lunes a Sábado 11:00 a 19:00 hrs. Domingo 11:00 a 18:00 hrs.", "relatedIds": ["la-lia-pizza", "don-giorgio", "hotel-italia"]},
  "hostal-casona-campos": {"description": "Hostal ubicado en lugar céntrico de Ovalle, en barrio ferroviario, cercano a Museo, Feria Modelo, Supermercados, bibliotecas entre otros. Barrio Familiar.", "phone": "(56) 9 42506659", "email": "lacasonacampos@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hostal-las-majadas", "hotel-italia"]},
  "hostal-las-majadas": {"description": "La tranquilidad de la Hacienda Las Majadas te invitará al descanso, y encuentro con la naturaleza, además de una conexión con la fauna y flora que abunda en este oasis dentro del Valle del Limari (uno de los atractivos más importantes de la IV Región). La crianza de cabras y fabricación artesanal de queso que se desarrolla en nuestra hacienda te entregará una oportunidad única de conocer este hermoso rubro, tan característico de esta región. Así como disfrutar de nuestro rico Queso Las Majadas. Te esperamos para compartir las maravillas del campo y su gente, bajo un cielo estrellado y en un ambiente de total tranquilidad.", "phone": "(56) 9 8129 7729", "email": "hostallasmajadas@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hotel-italia", "hostal-casona-campos"]},
  "hotel-altos-de-tuqui": {"description": "Que tal una estancia en las Cabañas Altos de Tuqui, muy cerca de donde todo lo bueno ocurre en Ovalle. Está ubicada sobre la Av. Manuel Peñafiel #2746 en una de las zonas de mayor tránsito y con mejor ubicación de la comuna. El recinto cuenta con 12 cabañas emplazadas en un entorno campestre y rural para disfrutar del clima del valle. Cada cabaña es independiente y posee sus propios servicios para garantizar tu comodidad y descanso placentero. Puedes preparar tus alimentos en la cocina equipada, descansar y ver tv en la sala, además cuenta con baños privados y ducha cliente. 2 dormitorios poseen cada cabaña, una cama matrimonial en la suite y camas separadas en la habitación secundaria. Amplios espacios de áreas verdes con jardín están a disposición de los huéspedes para realizar caminatas o descansar y disfrutar del ambiente natural. Los más pequeños pueden disfrutar en al área de juegos infantiles, si quieres hacer una celebración o fiesta familiar el área de quinchos con parrilla están a tu entera disposición. La piscina es el lugar perfecto cuando el sol está en su máximo esplendor y por las tardes o mañanas puedes relajarte en la tina de hidromasaje.", "phone": "(56) 9 95290795", "email": "contacto@altosdetuqui.cl", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hacienda-huamalata", "hotel-florencia", "hotel-termas-socos", "ovalle-suite", "keo-hotel", "hotel-limari"]},
  "hotel-american": {"description": "Ubicado en el corazón de Ovalle, en la emblemática calle Vicuña Mackenna, el Hotel American es la opción ideal para quienes buscan comodidad y accesibilidad. A solo minutos de la Plaza de Armas y la Alameda, nuestro hotel ofrece habitaciones luminosas con baño privado y TV. Además, contamos con un exclusivo estacionamiento y salones para eventos o charlas, todo pensado para brindarte una experiencia única.", "phone": "(56) 9 94043088", "email": "hotelamerican.0108@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hacienda-huamalata", "hotel-florencia", "hotel-termas-socos", "ovalle-suite", "keo-hotel", "hotel-limari"]},
  "hotel-florencia": {"description": "El Hotel Florencia se encuentra en una ubicación privilegiada en Ovalle , lo que facilita el acceso a diversas atracciones locales y actividades turísticas. Este hotel permite a los visitantes explorar la región de Coquimbo y disfrutar de su belleza natural, cultura y gastronomía.", "phone": "(56) 9 97306313", "email": "florenciahotel@gmail.com", "schedule": "Consultar horario con el establecimiento"},
  "hotel-italia": {"description": "Hotel Italia esta cerca del centro de Ovalle, Plaza de Armas. La estructura es simple y ofrece precios baratos. Hotel Italia cuenta con 21 dormitorios (dobles, individuales), todas ellas con ropa de cama y servicio de limpieza, televisión y baño privado con ducha. Hotel Italia también hay un restaurante de pizzas donde puede disfrutar de una buena pizza preparada de acuerdo con la mejor tradición italiana y excelentes platos a base de pasta (ravioli, lasaña, ñoquis, fettuccine, etc.). Con una noche de alojamiento, el desayuno está incluido, el horario de check-in es a las 14:00, el horario de check-out es a las 12.00. La propiedad se encuentra cerca del centro y de las principales atracciones turísticas del lugar.", "phone": "+56 9 57572323", "email": "inversionestapiaspa.77@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hacienda-huamalata", "hotel-florencia", "hotel-termas-socos", "ovalle-suite"]},
  "hotel-limari": {"description": "Hotel Limarí te espera como la mejor opción en la zona del Valle de Limarí para que puedas disfrutar tanto el turismo maravilloso de la zona, como tus reuniones de trabajo y asuntos corporativos. La maravillosa arquitectura del hotel está inspirada en culturas ancestrales de la zona, y su decoración interior ha sido minuciosamente seleccionada con elementos diaguitas y característicos del entorno. Estamos ubicados en el Km 5 de la Ruta D-55 Camino a Sotaqui, en el Sector Viñitas. Hotel Limarí cuenta con 38 Habitaciones de Categoría Superior y 2 Junior Suite. Amplio Lobby de acceso con una linda vista a nuestros jardines. Además de 2 Salas de Eventos y Reuniones con capacidad máxima de hasta 50 personas. Restaurant – Bar junto a la Terraza, Wifi en todas las áreas, Sala de ejercicios y Piscina externa junto a nuestros jardines, además de un amplio estacionamiento , el mismo se encuentra sujeto a disponibilidad.", "phone": "+56 9 76692327", "email": "reservas@hotellimari.cl", "relatedIds": ["hacienda-huamalata", "hotel-florencia", "hotel-termas-socos", "ovalle-suite"]},
  "iglesia-san-vicente": {"description": "La Iglesia San Vicente Ferrer de Ovalle es un símbolo arquitectónico y espiritual del Limarí, testigo de la historia, reconstrucciones y resiliencia de la comunidad. Aunque aún no está accesible por dentro, su fachada, torre y ubicación privilegiada hacen de este templo un punto turístico relevante para quienes visitan Ovalle.", "schedule": "CORROBORAR Mapa Iglesia San Vicente Ferrer La Iglesia San Vicente Ferrer de Ovalle es un símbolo arquitectónico y espiritual del Limarí, testigo de la historia, reconstrucciones y resiliencia de la comunidad. Aunque aún no está accesible por dentro, su fachada, torre y", "relatedIds": ["pueblo-barraza", "museo-limari", "valle-encanto"]},
  "info-clima": {"description": "Ovalle se caracteriza por un clima mediterráneo semiárido, con cielos mayormente despejados y temperaturas agradables durante gran parte del año. Gracias a su clima estable, Ovalle es un destino perfecto durante todo el año, combinando mañanas frescas, tardes soleadas y un cielo limpio que favorece el astroturismo y la contemplación de los paisajes naturales del valle del Limarí."},
  "info-oficina": {"description": "Actualmente la O ficina de I nformación T urística está ubicada en el Museo del Limarí, e n el “Salón de Extensión Patrimonial”. martes a viernes de 10:0 0 a 14:00 y de 15:00 a 18:00 hrs , sábado de 10:00 a 14:00 hrs .", "schedule": "de atención martes a viernes de 10:0 0 a 14:00 y de 15:00 a 18:00 hrs , sábado de 10:00 a 14:00 hrs ."},
  "info-terminal": {"description": "Cuando te encuentras en el Terminal Ovalle recuerda cuidar tus pertenencias, sobre todo en momentos de gran afluencia de personas. También debes estar atento a las llegadas de los buses en el Terminal Ovalle, ya que la mayoría de los terminales no informa sobre la llegada. martes a viernes de 10:0 0 a 14:00 y de 15:00 a 18:00 hrs , sábado de 10:00 a 14:00 hrs ."},
  "kata-resto-bar": {"description": "Kata bar se destaca por su calidad en comida casera, y ambiente familiar puede disfrutar de excelentes precios, espacios adap tados para sillas de ruedas y coches .", "schedule": "Lunes a jueves de 09:30 a 01:00 hrs. Viernes y sábado de 09:30 a 03:00 hrs. Domingo cerrado.", "relatedIds": ["la-lia-pizza", "don-giorgio", "hotel-italia"]},
  "keo-hotel": {"description": "En Ovalle Casino & Resort encontrarás la perfecta combinación de relax, entretención y oportunidades de negocios. Keo Hotel dispone de diversas propuestas de gastronomía, spa, piscina, gimnasio, salas de eventos & centro de convenciones, además de casino y shows, para ofrecer a sus huéspedes una completa experiencia de entretención, calidez y confort. Ovalle Casino Resort es más que una experiencia inolvidable: reúne lo mejor de la hotelería, la gastronomía, la observación astronómica, el entretenimiento y wellness en un entorno ideal. Déjate sorprender por la belleza de su arquitectura y el confort de un hotel moderno, con un servicio de excelencia.", "phone": "(56) 9 65698875", "email": "reservas@ovallecasinoresort.cl"},
  "la-lia-pizza": {"description": "Ganadora del primer lugar en la competencia «Mejor pizza de Ovalle 2024», es una pizzería familiar que trabaja con masas de larga fermentación, ingredientes frescos, queso sin lactosa y pizzas estilo portafoglio , todo esto horneado en hornos napolitanos. Ubicada en la calle principal de nuestra ciudad a unos pasos de la plaza de armas.", "phone": "+56 9 55164766", "email": "laliapizzas@gmail.com", "schedule": "Martes, miércoles y jueves de 14:00 a 21:30 hrs. Viernes de 14:00 a 22:30 hrs. Sábado de 17:30 a 22:30 hrs. Domingo de 17:30 a 21:30 hrs.", "relatedIds": ["don-giorgio", "hotel-italia"]},
  "limari-aventura": {"description": "Limarí Aventura, es un emprendimiento asociativo que ofrece una variedad de actividades de turismo de Intereses Especiales en el Valle del Limarí, con guías locales de Ovalle y Monte Patria. Se centran en la conexión con el patrimonio cultural, natural y sideral de la provincia, resaltando el patrimonio arqueológico de nuestros pueblos originarios, y los sitios con arte rupestre. Entre las actividades disponibles incluyen tours a sitios patrimoniales, trekking diurnos y nocturnos, incluyendo astroturismo cultural y destacando el privilegio de la zona sus cielos oscuros y zonas Starlight. El enfoque es en la educación ambiental y la conservación del ecosistema, además de fomentar un turismo responsable y significativo que beneficie a la comunidad local. Tour operador cuenta con Monitor de Astroturismo Certificado Starlight, lo que garantiza experiencias de observación astronómica guiadas bajo estándares internacionales de calidad y protección del cielo nocturno.", "phone": "+56 9 64096784", "email": "turismo.limariaventura@gmail.com", "relatedIds": ["turismo-huerta", "limari-travel", "viento-sur", "turismo-diaguitas", "limari-experience"]},
  "limari-experience": {"description": "Descubre y vive la experiencia Limarí, recorriendo la provincia de mar a cordillera, entre valles escondidos, diversidad de paisajes y cielos estrellados, sorpréndete lugares visitándonos en un trekking escalada de roca, kayak o en cualquiera de sus entretenidos tour. Operadores locales, promueven nuestros territorio y patrimonio, la provincia del Limarí.", "phone": "(56) 9 32336366", "email": "limariexperience@gmail.com", "relatedIds": ["limari-aventura", "turismo-huerta", "limari-travel", "viento-sur", "turismo-diaguitas"]},
  "limari-travel": {"phone": "(56) 9 78801089", "email": "contacto.limaritravel@gmail.com", "relatedIds": ["limari-aventura", "turismo-huerta", "viento-sur", "turismo-diaguitas", "limari-experience"]},
  "los-pumas-encanto": {"description": "No cuentan con leña o carbón, este insumo lo debe traer el cliente. Ubicado a solo 21 km de Ovalle, en el sector Campo Lindo y a pasos del enigmático Valle del Encanto, se encuentra el Camping y Cabañas Los Pumas del encanto, un espacio ideal para disfrutar de la naturaleza, el descanso y la entretención al aire libre. Este lugar ofrece diversas experiencias para toda la familia y grupos de amigos, entre ellas:", "phone": "+56961509957", "schedule": "09:30 a 20:00 hrs. Además, los visitantes pueden adquirir productos locales como aceite oliva extra virgen, licor de oliva, aceitunas preparadas entre otros.", "details": ["Paintball: Diversión asegurada con todo el equipamiento necesario para hasta 12 personas. (Marcadoras con 100 paintball, overol, guantes, protector facial y pecheras)", "Camping: Con quinchos equipados, baños, energía eléctrica, mesas y sillas, además de áreas diseñadas para una estadía cómoda en contacto con la naturaleza. Horario 13:00 a 12:00 hrs.", "Cabañas: Totalmente equipadas, ideales para grupos o familias que buscan mayor comodidad. Horario 13:00 a 12:00 hrs.", "Piscina disponible todos los días $6.000 por persona. Horario 09:30 a 20:00 hrs.", "Además, los visitantes pueden adquirir productos locales como aceite oliva extra virgen, licor de oliva, aceitunas preparadas entre otros."], "relatedIds": ["viento-sur", "trapiche-lodge", "descanso-antakari", "cabanas-stommeln", "cabanas-fray-jorge"]},
  "macero-sour": {"relatedIds": ["pisco-ovalle", "vina-tololo", "espumante-azur", "cooperativa-pisquera"]},
  "museo-limari": {"description": "El Museo del Limarí es un referente cultural del valle del Limarí que combina una colección arqueológica notable con un espacio arquitectónico histórico y una programación educativa activa. Perfecto para quienes buscan una experiencia cultural profunda en Ovalle.", "phone": "(56) 512 662282", "email": "museo.limari@museoschile.gob.cl", "schedule": "CORROBORAR Mapa Museo del Limarí El Museo del Limarí es un referente cultural del valle del Limarí que combina una colección arqueológica notable con un espacio arquitectónico histórico y una programación educativa activa. Perfecto para quienes buscan una experiencia cultural profunda en Ovalle.", "relatedIds": ["pueblo-barraza", "iglesia-san-vicente", "valle-encanto"]},
  "ovalle-suite": {"description": "Hostal Boutique Ovalle Suite está ubicado en una casona con historia, totalmente remodelada y elegante, manteniendo su esencia, en un ambiente moderno, diseño sofisticado y seguro. Cuenta con conexión wifi gratuita y está ubicado en calle Carmen número 176, Calle que queda a una cuadra de la hermosa plaza de Armas de la ciudad de Ovalle ,a una cuadra de los distintos centros financieros, comerciales y atractivos culturales, como bancos , notarias, tiendas comerciales , restaurantes y teatro municipal, entre otros . Contamos con 8 habitaciones las cuales están decoradas con sutiles colores, diseño elegante, ecológico y funcional con los más delicados detalles realizados por artesanos de este hermoso valle.", "phone": "(56) 9 87594277", "email": "ovallesuite@gmail.com", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["hacienda-huamalata", "hotel-florencia", "hotel-termas-socos", "keo-hotel", "hotel-limari", "hotel-american"]},
  "parque-penones": {"description": "El parque recreacional Los Peñones es un querido espacio municipal situado en Ovalle, en la Región de Coquimbo. Popular por sus áreas verdes a la ribera del rí o L imarí , es ideal para asados familiares, paseos y actividades al aire libre.", "relatedIds": ["desembocadura-limari", "fray-jorge"]},
  "pisco-ovalle": {"description": "El Pisco Ovalle es un destilado Premium elaborado artesanalmente en el corazón del Valle del Limarí, una de las zonas pisqueras más reconocidas de Chile. Su proceso de producción combina tradición y dedicación, dando vida a un pisco reservado de 40°, con notas de madera, frutas y hierbas que reflejan la riqueza del terroir local. De sabor suave y equilibrado, es ideal para disfrutar en cócteles o solo, resaltando la calidad y carácter de la uva pisquera del Limarí. Con una elegante presentación y un fuerte arraigo en la identidad ovallina, este pisco representa el orgullo y la tradición de la comuna.", "relatedIds": ["macero-sour", "vina-tololo", "espumante-azur", "cooperativa-pisquera"]},
  "pisco-waqar": {"description": "Elaborado por Pisquera Tulahuén con 170 años de tradición, PISCO WAQAR es un destilado ultra premium con denominación de origen, elaborado a escala humana a partir de vino chileno, obtenido 100% de uvas moscatel cultivadas en un terruño puro y ancestral a los pies de los Andes, y aun cosechadas a mano. A los sentidos WAQAR es transparente, joven y prístino, fino y delicado, con cautivantes aromas a frutas blancas, cítricos y azahares. Al beber revela un delicioso sabor, redondo y seco, sin ardor molesto los aromas se desparraman en la boca transportándonos a la fruta fresca de los viñedos mientras un leve picor pincha los sentidos, al irse deja un grato recuerdo por un instante prolongado que se desvanece lenta y sutilmente.", "phone": "+569 85700189", "email": "CONTACTO@PISQUERATULAHUEN.CL", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "pisquera-tulahuen": {"description": "La Pisquera Tulahuén es reconocida por elaborar dos de los piscos más destacados de Chile: Pisco Waqar y Pisco Heron . Con una tradición familiar y un proceso de producción artesanal, esta pisquera combina el saber ancestral con técnicas modernas para crear destilados de calidad internacional. Su ubicación en la localidad de Tulahuén, Monte Patria, le otorga características únicas, ya que las uvas crecen bajo cielos despejados y en un clima privilegiado que potencia sus aromas y sabores. Visitar la Pisquera Tulahuén es una experiencia donde se puede conocer de cerca el proceso de destilación, recorrer sus instalaciones y, por supuesto, degustar piscos que han sido reconocidos en competencias nacionales e internacionales por su elegancia y autenticidad.", "phone": "+569 85700189", "email": "CONTACTO@PISQUERATULAHUEN.CL", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "plaza-terraza": {"description": "Plaza Terraza se encuentra emplazada en una de las mejores ubicaciones de la ciudad, ofreciendo una amplia terraza con una vista privilegiada hacia la hermosa plaza de Ovalle. Este gastrobar utiliza ingredientes de calidad para llevar el mejor sabor a la mesa de sus clientes. Se destaca por su elegante infraestructura, buena atención, cortes de carnes angus black , exquisitas pizzas, las mejores hamburguesas smash y una variada carta de ensaladas, platos fríos y café.", "phone": "+56 9 33664217", "schedule": "Lunes de 09:00 a 23:00 hrs. Martes a jueves de 09:00 a 01:00 hrs. Viernes y sábado de 09:00 a 03:00 hrs. Domingo cerrado.", "relatedIds": ["la-lia-pizza", "don-giorgio", "hotel-italia"]},
  "poki-bubble-tea": {"description": "Poki Bubble Tea ofrece una propuesta diferente en Ovalle: una cafetería asiática que combina sabores auténticos de Corea, Japón y China, invitando a sus visitantes a descubrir una experiencia única llena de aroma, color y sabor.", "schedule": "Lunes a viernes 09:30 a 20:30 hrs. Sábado a domingo 10:30 a 20:30 hrs.", "relatedIds": ["riquisimo", "cabildo-abierto", "plaza-terraza", "kata-resto-bar"]},
  "pueblo-barraza": {"description": "El Pueblo de Barraza es una joya colonial del Valle del Limarí. Su gran valor histórico reside en la armoniosa conservación de su arquitectura, su trazado urbano y su población que preserva vivo el legado cultural. La Iglesia de San Antonio del Mar , junto con celebraciones populares y museos locales, lo convierten en un destino imperdible para quienes buscan experiencia, autenticidad y patrimonio en la Región de Coquimbo.", "schedule": "Iglesia 09:00 a 18:00 hrs. Mapa Pueblo de Barraza El Pueblo de Barraza es una joya colonial del Valle del Limarí. Su gran valor histórico reside en la armoniosa conservación de su arquitectura, su trazado urbano y su población que preserva vivo el legado cultural. La Iglesia de San Antonio del Mar , junto con celebraciones populares y museos locales, lo convierten en un destino imperdible para quienes buscan experiencia, autenticidad y patrimonio en la Región de Coquimbo.", "relatedIds": ["iglesia-san-vicente", "museo-limari", "valle-encanto"]},
  "qori-aceite": {"description": "Es un producto gourmet de excelencia, fruto del cli ma único del Li ma rí, de un blend cuida doso y una extracción industrial especializada. Ideal para quienes buscan un aceite fresco, equilibrado y con carácter, accesible desde su origen en Ovalle hasta mesas exigentes.", "phone": "(56) 9 92222054", "email": "claudimoreno@qori.cl", "relatedIds": ["macero-sour", "pisco-ovalle", "cooperativa-pisquera"]},
  "rincon-de-los-postres": {"description": "Rincón de los postres es una pastelería y Cafetería Vintage con 8 años al servicio de nuestra clientela, cuentan con una amplia variedad de pasteles y postres entre los que destacan: Brownies con diferentes rellenos, gran variedad de galletas, alfajores, bombones, macarrons, mini tortas, pie de limón, cheesecake; su producto estrella es la torta amor. Además, cuentan con excelente atención, puedes pedir para llevar o servir tus pasteles favoritos. Fuera de los pasteles también tienen a la venta una variedad de preciosa loza vintage inglesa.", "phone": "+56 9 74315502", "email": "rincondelospostresovalle@gmail.com", "schedule": "Lunes a sábado 08:00 a 20:00 hrs.", "relatedIds": ["poki-bubble-tea", "cafe-carmen", "blackcoffe", "cafe-vittoria"]},
  "rincon-del-sushi": {"description": "Rincón del sushi es una empresa familiar Ovallina dedicada a la venta de sushi como la famosa sushi burger, ceviches, sushipleto, gohan, hand roll, y muchas más promociones.", "phone": "+56 9 46324426", "email": "elrincondelsushi20@gmail.com", "schedule": "Lunes a domingo 10:00 a 00:00 hrs.", "relatedIds": ["scart-sushi"]},
  "riquisimo": {"description": "Riquísimo Restaurant & Sandwichería Ovalle, abre sus puertas el 05 de septiembre del año 2011, ubicado en calle Coquimbo 136, cerca de la plaza de Armas, Ovalle – IV Región – Chile. En una casona antigua que data del siglo XIX. Iniciaron entregando servicio de comida para llevar, luego nos convertimos en un reconocido Restaurant & Sandwichería de la ciudad de Ovalle, que puede albergar en la actualidad a más de 100 personas sentadas cómodamente sentadas. Además, brindan alimentación a empresas, servicio de coctelería – banquetería y reparto a domicilio. Su espacio es ideal para celebraciones de fiestas de fin de año, cumpleaños y festejos en general. Su objetivo es brindar un servicio de calidad hacia el cliente, con productos locales finamente seleccionados y excelencia en la atención, además pretenden ser un precedente turístico cultural, por lo mismo, creamos espacios para dar cabida a distintos artistas locales y así crear un entorno agradable para quienes los visiten y puedan disfrutar de una excelente gastronomía y de una experiencia inolvidable.", "phone": "(+56) 9 44947786", "email": "restaurant.riquisimo@gmail.com", "schedule": "Lunes a Viernes de 08:30 a 21:30 hrs. Sábados de 11:00 a 21:30 hrs.", "relatedIds": ["la-lia-pizza", "don-giorgio", "hotel-italia"]},
  "scart-sushi": {"description": "Scart Sushi es una innovadora propuesta gastronómica ovallina, ubicada en El Portal. Con tan solo 6 meses de funcionamiento, este restaurante ha sabido destacar no solo por su variada carta, sino también por su original temática inspirada en la cantante Karol G, promoviendo el empoderamiento femenino en cada rincón del local. Especializado en sushi, Scart Sushi ofrece una amplia variedad de preparaciones como rolls acevichados, rolls premium, tablas, barcos de sushi, sushi burgers, gohan y sushipleto. Además, pensando en quienes prefieren otras alternativas, también cuentan con opciones como papas fritas, pollo frito, arrollados primavera, y papas con salsa blanca de camarón, entre otros.", "phone": "+56 9 3506 3888", "email": "scartsushi@gmail.com", "schedule": "Lunes a domingo de 10:00 Am a 00:00 hr s .", "relatedIds": ["la-lia-pizza", "don-giorgio", "hotel-italia"]},
  "trapiche-lodge": {"description": "Trapiche Lodge es un complejo de turismo wellness ubicado a 13 kms. del centro de Ovalle, en un entorno natural privilegiado del Valle del Limarí. Cuenta con 4 cabañas de diseño rústico-moderno (para 2, 4 y hasta 6 personas), gran piscina recreativa, zona de Spa al aire libre con tinas calientes, pozón ideal para practicar stand up paddle (servicio incluido en el alojamiento), sala de eventos equipada para hasta 100 personas, cancha de fútbol y otras entretenciones. Ofrecemos experiencias de relajación y aventura, perfectas para parejas, familias y grupos que buscan desconectarse y reconectar con la naturaleza, así como también para grupos que buscan algún tipo de celebración o evento.", "phone": "(56) 9 67281723", "email": "contacto@trapichelodge.cl", "schedule": "Consultar horario con el establecimiento", "relatedIds": ["los-pumas-encanto", "viento-sur", "descanso-antakari", "cabanas-stommeln", "cabanas-fray-jorge"]},
  "turismo-diaguitas": {"description": "Turismo Diaguitas es un tour operador enfocado a la cultura en general, especializado en patrimonio natural y cultural del valle de Limarí. Nuestra misión es superar las expectativas del cliente entregando información de manera entretenida y con fuentes confiables.", "phone": "(56) 9 34513896", "email": "dturismo9@gmail.com", "relatedIds": ["limari-aventura", "turismo-huerta", "limari-travel", "viento-sur", "limari-experience"]},
  "turismo-huerta": {"description": "Turismo Huerta es un tour operador de la Provincia de Limarí con más de 6 años de experiencia en la organización de recorridos hacia los principales atractivos naturales y culturales de Ovalle. Entre ellos destacan el Parque Nacional Fray Jorge, el Valle del Encanto, la desembocadura del río Limarí, visitas a viñas y queserías locales, además de experiencias de astroturismo en la reserva Starlight Ojo de Agua. Contamos con modernas vans y guías certificados, expertos en flora, fauna y patrimonio local, lo que nos permite ofrecer un servicio seguro, cómodo y enriquecedor. Nuestro objetivo es brindar a cada visitante una experiencia auténtica e inolvidable en el corazón del Limarí.", "phone": "(56) 9 52146572", "email": "turismohuerta@hotmail.com", "relatedIds": ["limari-aventura", "limari-travel", "viento-sur", "turismo-diaguitas", "limari-experience"]},
  "valle-encanto": {"description": "Ubicado a 15 kilómetros al suroeste de Ovalle, el Valle del encanto es un sitio arqueológico de gran relevancia patrimonial y cultural. En medio de un paisaje semidesértico, este lugar resguarda vestigios de culturas precolombinas, especialmente de los pueblos El Molle y Diaguita, con manifestaciones como petroglifos, pictografías y piedras tacitas. El entorno natural del valle, marcado por formaciones rocosas, vegetación nativa y un arroyo estacional, invita a la contemplación y al recorrido pausado. Ideal para quienes buscan experiencias de turismo cultural, historia ancestral y contacto con la naturaleza. El Valle del Encanto ha sido declarado Monumento Nacional, y representa una ventana única al pasado prehispánico del norte de Chile.", "details": ["A continuación, detallamos algunas consideraciones importantes para la visita, a fin de preservar y respetar el entorno del Monumento:"]},
  "viento-sur": {"description": "Alojamiento & Experiencias diurnas y nocturnas para conectarse con la naturaleza. A solo 11 kilómetros del Parque Nacional Fray Jorge , descubre tu refugio en la Galaxia donde el silencio y la naturaleza se unen para despertar emociones únicas. Rodeados de una rica biodiversidad, siente y vive en armonía con el entorno. Bajo cielos estrellados y limpios de contaminación lumínica certificados por la UNESCO, cada noche se convierte en una experiencia mágica que transformará tu forma de ver el universo.", "phone": "+56 9 49895921", "email": "vientosurastrocamping@gmail.com", "relatedIds": ["limari-aventura", "turismo-huerta", "limari-travel", "turismo-diaguitas", "limari-experience"]},
  "viento-sur-operador": {"description": "Alojamiento & Experiencias diurnas y nocturnas para conectarse con la naturaleza. A solo 11 kilómetros del Parque Nacional Fray Jorge , descubre tu refugio en la Galaxia donde el silencio y la naturaleza se unen para despertar emociones únicas. Rodeados de una rica biodiversidad, siente y vive en armonía con el entorno. Bajo cielos estrellados y limpios de contaminación lumínica certificados por la UNESCO, cada noche se convierte en una experiencia mágica que transformará tu forma de ver el universo.", "phone": "+56 9 49895921", "email": "vientosurastrocamping@gmail.com", "relatedIds": ["limari-aventura", "turismo-huerta", "limari-travel", "turismo-diaguitas", "limari-experience"]},
  "vina-dalbosco": {"description": "En un estrecho valle que cruza desde la cordillera de Los Andes hasta el Océano Pacífico, en el corazón del Valle del Limarí, en Punitaqui, se encuentra Viña Dalbosco. Este estrecho valle es un verdadero tesoro vitivinícola, reconocido por sus singulares microclimas que permiten obtener uvas de calidad excepcional. De ellas nacen una gran variedad de vinos elegantes, de intenso color, gran cuerpo y frutosidad que refleja la esencia del valle. Visitar Viña Dalbosco es más que una experiencia enológica: es un encuentro con la tradición, la naturaleza y la pasión por el vino. Te invitamos a recorrer nuestros viñedos, descubrir los secretos de su elaboración y disfrutar de degustaciones que despiertan los sentidos.", "phone": "(56) 9 99979777", "email": "info@dalboscowines.cl", "schedule": "Horario continuado. Lunes a jueves de 8:30 a 18:00 hrs. Viernes de 8:30 a 17:00 hrs. Sábado de 10:00 a 14:00 hrs.", "details": ["Ven, descubre y vive la magia del Valle del Limarí a través de los vinos…", "Disponibilidad de tours: Si, con aviso previo (no tenemos capacidad máxima porque hemos atendido buses de adultos mayores)."], "relatedIds": ["macero-sour", "pisco-ovalle", "vina-tololo", "espumante-azur"]},
  "vina-ochotierras": {"description": "Viña OchoTierras ofrece una experiencia auténtica y enriquecedora para los amantes del vino. Su producción limitada, combinada con el entorno único del Valle del Limarí, hacen de esta viña un destino imperdible para quienes buscan conocer la esencia del enoturismo chileno. Realizan tour con previa reserva, mínimo 4 personas y máximo 12 personas.", "phone": "+56 9 95422781", "email": "info@ochotierras.cl", "schedule": "Sala de Ventas Lunes a viernes 08:30 a 17:25 hrs. Horario Tour Lunes a sábado 10:00 – 11:00 aprox. Duración 3 horas aproximadamente. Solo con reservas", "relatedIds": ["macero-sour", "pisco-ovalle", "vina-tololo", "espumante-azur"]},
  "vina-soler": {"description": "Empresa familiar, orientada a la producción de vinos con fuerte identidad local, han sacado aplausos entre los críticos gastronómicos gracias a sus viñedos jóvenes ubicados en la comuna de Punitaqui, que logran sabrosas uvas gracias a su suelo franco arcillo limoso y excepcional clima originado por las diferencias de temperaturas entre los días soleados y las noches frías. Mezcla perfecta de tierra y clima, que sumado al esmero del manejo del viñedo y a un proceso de elaboración de alta tecnología, permite obtener vinos de características únicas e inigualables.", "phone": "(56) 9 81998534", "email": "punitaqui@vinasoler.cl", "relatedIds": ["macero-sour", "pisco-ovalle", "vina-tololo", "espumante-azur"]},
  "vina-tabali": {"description": "Tabali es una viña familiar, fundada por Guillermo Luksic en 2002, dedicada exclusivamente a la producción de vinos de terroir que expresan con pureza y precisión su lugar de origen. Desde sus inicios, el propósito ha sido claro: elaborar vinos de alta calidad que reflejen el carácter único de sus suelos y climas, y que al ser degustados logren transportar a quien los prueba directamente a los viñedos de Tabali.", "schedule": "Sabado 11:00AM – 16:00PM", "relatedIds": ["macero-sour", "pisco-ovalle", "vina-tololo", "espumante-azur"]},
  "vina-tololo": {"description": "Viña Tololo representa la esencia del Valle del Limarí, combinando tradición, innovación y un respeto profundo por su entorno. Ya sea para los amantes del vino, los entusiastas del pisco o aquellos interesados en el enoturismo, una visita a esta viña promete una experiencia enriquecedora y memorable.", "phone": "(+56) 9 38693973", "email": "ventas@tololovinos.cl", "relatedIds": ["macero-sour", "pisco-ovalle", "espumante-azur", "cooperativa-pisquera"]},
} as const;
